import akka.actor.ActorSystem
import akka.http.scaladsl.Http
import akka.http.scaladsl.model.{HttpRequest, HttpResponse}

object WebhookProxyService extends App {
  implicit val system: ActorSystem = ActorSystem("webhook-proxy-service")

  val route = {
    post {
      entity(as[String]) { userUrl =>
        Http().singleRequest(HttpRequest(uri = userUrl))
          .map { response: HttpResponse =>
            complete(response.entity.toString)
          }
      }
    }
  }

  Http().newServerAt("localhost", 8080).route(route).start()
}